<?php

namespace App\Http\Middleware;

use Closure;
use Illuminate\Support\Facades\Cookie;

class UserPreferencesMiddleware
{
    public function handle($request, Closure $next)
    {
        // Check if the cookie exists and unserialize it
        if (Cookie::has('user_prefs')) {
            $preferences = unserialize(Cookie::get('user_prefs'));
            session(['user_preferences' => $preferences]);
        }

        return $next($request);
    }
}

// In your controller or wherever you need to set preferences
public function setUserPreferences()
{
    $preferences = [
        'theme' => 'dark',
        'language' => 'en',
        // Add more preferences as needed
    ];

    // Serialize the preferences and store them in a cookie
    Cookie::queue('user_prefs', serialize($preferences), 60 * 24 * 30); // 30 days

    return redirect()->back();
}